from __future__ import annotations

from dataclasses import dataclass


@dataclass
class Task:
    id: str
    title: str
    completed: bool = False
    attempts: int = 0


def validate_task(task: Task) -> None:
    if not task.id or not task.id.strip():
        raise ValueError("task id is required")
    if "/" in task.id or "\\" in task.id:
        raise ValueError("task id must be a simple identifier")
    if not task.title or not task.title.strip():
        raise ValueError("task title is required")

from __future__ import annotations

from task_service.model import Task, validate_task


class TaskService:
    def __init__(self, tasks: list[Task] | None = None):
        self.tasks = tasks or []

    def add(self, task: Task) -> None:
        validate_task(task)
        if any(existing.id == task.id for existing in self.tasks):
            raise ValueError("duplicate task id")
        self.tasks.append(task)

    def get(self, task_id: str) -> Task:
        for task in self.tasks:
            if task.id == task_id:
                return task
        raise ValueError(f"unknown task id: {task_id}")

    def complete(self, task_id: str) -> bool:
        self.get(task_id).completed = True
        return True

    def retry(self, task_id: str) -> int:
        task = self.get(task_id)
        task.attempts += 1
        return task.attempts

from __future__ import annotations

import argparse
from pathlib import Path

from task_service.model import Task
from task_service.service import TaskService
from task_service.storage import load_tasks, save_tasks


def _require_id(parser: argparse.ArgumentParser, value: str | None) -> str:
    if not value:
        parser.error("--id is required")
    return value


def main() -> None:
    parser = argparse.ArgumentParser()
    parser.add_argument("command", choices=["add", "list", "complete", "retry", "get"])
    parser.add_argument("--db", default="tasks.json")
    parser.add_argument("--id")
    parser.add_argument("--title")
    args = parser.parse_args()

    db = Path(args.db)
    service = TaskService(load_tasks(db))
    try:
        if args.command == "add":
            service.add(Task(id=args.id or "", title=args.title or ""))
            save_tasks(db, service.tasks)
        elif args.command == "complete":
            service.complete(_require_id(parser, args.id))
            save_tasks(db, service.tasks)
        elif args.command == "retry":
            attempts = service.retry(_require_id(parser, args.id))
            save_tasks(db, service.tasks)
            print(attempts)
        elif args.command == "get":
            task = service.get(_require_id(parser, args.id))
            print(f"{task.id}: {task.title} completed={task.completed} attempts={task.attempts}")
        else:
            for task in service.tasks:
                print(f"{task.id}: {task.title} completed={task.completed} attempts={task.attempts}")
    except ValueError as exc:
        parser.error(str(exc))


if __name__ == "__main__":
    main()
